    public static void main(final String[] args) throws Exception {
        final LogContext logContext = new LogContext("test ");
        // Small cache so puts trigger evictions quickly
        final long smallCacheSize = 200L;
        final ThreadCache cache = new ThreadCache(logContext, smallCacheSize, new MockStreamsMetrics(new Metrics()));
        final String namespace1 = "0.0-store1";
        final String namespace2 = "0.1-store2";

        // Flush listener for namespace1: when entries are evicted/flushed, write into namespace2.
        // This simulates a downstream processor writing to another state store during flush.
        cache.addDirtyEntryFlushListener(namespace1, dirty -> {
            for (final ThreadCache.DirtyEntry entry : dirty) {
                cache.put(namespace2, entry.key(),
                    new LRUCacheEntry(entry.newValue(), new RecordHeaders(), true, 0L, 0L, 0, "", new byte[0], new byte[0]));
            }
        });

        // Flush listener for namespace2: write into namespace1.
        cache.addDirtyEntryFlushListener(namespace2, dirty -> {
            for (final ThreadCache.DirtyEntry entry : dirty) {
                cache.put(namespace1, entry.key(),
                    new LRUCacheEntry(entry.newValue(), new RecordHeaders(), true, 0L, 0L, 0, "", new byte[0], new byte[0]));
            }
        });

        // Thread 1: continuously puts entries, triggering evictions and flush callbacks
        final Thread putter = new Thread(() -> {
            for (int i = 0; i < 50; i++) {
                final Bytes key = Bytes.wrap(new byte[]{(byte) i});
                final byte[] value = new byte[50];
                cache.put(namespace1, key,
                    new LRUCacheEntry(value, new RecordHeaders(), true, 0L, 0L, 0, "", new byte[0], new byte[0]));
            }
        }, "putter-thread");

        // Thread 2: continuously resizes the cache, acquiring ThreadCache lock then NamedCache lock
        final Thread resizer = new Thread(() -> {
            for (int i = 0; i < 50; i++) {
                cache.resize(smallCacheSize / 2);
                cache.resize(smallCacheSize);
            }
        }, "resizer-thread");

        putter.start();
        resizer.start();

        putter.join();
        resizer.join();
    }
}

